<!-- страница отзыва согласия на обработку ПДн -->
 <?php
session_start();
require_once __DIR__ . '/db.php';

// Если пользователь уже авторизован в админке, покажем шапку
$isAdmin = isset($_SESSION['admin_logged']) && $_SESSION['admin_logged'] === true;

$message = '';
$messageType = '';
$application = null;
$showForm = true;

// Получаем ID заявки из параметра
$applicationId = isset($_GET['id']) ? (int)$_GET['id'] : 0;

// Если ID передан, пытаемся найти заявку
if ($applicationId > 0) {
    try {
        $stmt = $pdo->prepare("
            SELECT a.*, v.title as vacancy_title 
            FROM applications a 
            LEFT JOIN vacancies v ON a.vacancy_id = v.id 
            WHERE a.id = ?
        ");
        $stmt->execute([$applicationId]);
        $application = $stmt->fetch();
        
        if (!$application) {
            $message = 'Заявка с таким ID не найдена.';
            $messageType = 'error';
            $showForm = false;
        }
    } catch (PDOException $e) {
        $message = 'Ошибка базы данных: ' . $e->getMessage();
        $messageType = 'error';
        $showForm = false;
    }
}

// Обработка формы отзыва согласия
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['confirm_withdraw'])) {
    $applicationId = (int)$_POST['application_id'];
    $phone = isset($_POST['phone']) ? trim($_POST['phone']) : '';
    
    if ($applicationId <= 0 || empty($phone)) {
        $message = 'Пожалуйста, заполните все поля.';
        $messageType = 'error';
    } else {
        try {
            // Находим заявку по ID и телефону
            $stmt = $pdo->prepare("
                SELECT a.*, v.title as vacancy_title 
                FROM applications a 
                LEFT JOIN vacancies v ON a.vacancy_id = v.id 
                WHERE a.id = ? AND a.answers_json LIKE ?
            ");
            
            // Ищем телефон в answers_json
            $phoneSearch = '%' . $phone . '%';
            $stmt->execute([$applicationId, $phoneSearch]);
            $foundApplication = $stmt->fetch();
            
            if (!$foundApplication) {
                $message = 'Заявка с указанным номером телефона не найдена. Проверьте правильность введённых данных.';
                $messageType = 'error';
            } else {
                // Обновляем запись: consent_granted = 0 (согласие отозвано)
                $updateStmt = $pdo->prepare("
                    UPDATE applications 
                    SET consent_granted = 0, 
                        consent_withdrawn_at = NOW(),
                        consent_withdrawn_ip = ?,
                        consent_withdrawn_user_agent = ?
                    WHERE id = ?
                ");
                
                $ip = $_SERVER['REMOTE_ADDR'] ?? null;
                $userAgent = $_SERVER['HTTP_USER_AGENT'] ?? null;
                
                $updateStmt->execute([$ip, $userAgent, $applicationId]);
                
                $message = "Согласие на обработку персональных данных успешно отозвано.\nДанные будут удалены из нашей системы в течение 30 дней с момента подачи заявки.";
                $messageType = 'success';
                $showForm = false;
                $application = $foundApplication;
            }
        } catch (PDOException $e) {
            $message = 'Ошибка при отзыве согласия: ' . $e->getMessage();
            $messageType = 'error';
        }
    }
}
?>

